  ('dietitian-moex-07006', 'dietitian', 'dietitian-moex-103-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '下列有關蛋白質功能的敘述，何者錯誤？ 製造核酸的主要碳源  維持體液的平衡  負責細胞生長及修復  幫助血液的凝固', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "03a6384fb1e1", "answer_pdf_sha1": "661e03be9c00", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "營養學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 6, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07007', 'dietitian', 'dietitian-moex-103-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '下列何種食物可以提供人體需要的所有必需胺基酸？ 小麥  大豆  玉米  牛奶', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "03a6384fb1e1", "answer_pdf_sha1": "661e03be9c00", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "營養學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 7, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07008', 'dietitian', 'dietitian-moex-103-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '下列何種方法無法造成蛋白質變性？ 加熱  加酸  加蛋白酶  加水', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "03a6384fb1e1", "answer_pdf_sha1": "661e03be9c00", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "營養學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 8, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07009', 'dietitian', 'dietitian-moex-103-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '有關反式脂肪的敘述，下列何者錯誤？ 天然食物中的脂肪酸雙鍵大部分為順式（cis）雙鍵 食用植物油進行氫化後，會增加反式之雙鍵結構，增加飽和度，減少油脂的酸敗機率 反式脂肪大部分來自加工食品，天然食物中不含反式脂肪 攝食過多的反式脂肪，可能會抑制必需脂肪酸的去飽和（desaturation）及鏈加長（elongation）反應', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "03a6384fb1e1", "answer_pdf_sha1": "661e03be9c00", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "營養學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 9, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07010', 'dietitian', 'dietitian-moex-103-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '下列何種食物的膽固醇最多？ 100克鮪魚肉  100克豬瘦肉  1顆雞蛋（60克）  100克豬肝', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "03a6384fb1e1", "answer_pdf_sha1": "661e03be9c00", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "營養學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 10, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07011', 'dietitian', 'dietitian-moex-103-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '下列有關高密度脂蛋白（HDL）的敘述，何者錯誤？ 血液中的HDL，大部分是由肝臟和小腸製造 四種脂蛋白中，HDL的蛋白質比例最低，體積最小 HDL膽固醇濃度高低和罹患心血管疾病的風險呈負相關 負責將周邊組織的膽固醇回收，運送回肝臟', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "03a6384fb1e1", "answer_pdf_sha1": "661e03be9c00", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "營養學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 11, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07012', 'dietitian', 'dietitian-moex-103-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '下列有關膽酸（bile acid）的敘述，何者最正確？ 在膽囊中，由膽固醇轉化而成 分泌至十二指腸後，可經由腸肝循環（enterohepatic circulation）回到肝臟 腸道再吸收的膽酸，經由淋巴系統送回肝臟 增加腸道膽酸的再吸收，將有助於減少血膽固醇濃度', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "03a6384fb1e1", "answer_pdf_sha1": "661e03be9c00", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "營養學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 12, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07013', 'dietitian', 'dietitian-moex-103-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '下列敘述何者錯誤？ 腰臀比與心血管疾病的發生率具相關性  老年人的腰圍與體內胰島素的敏感性密切相關 可利用Deurenberg公式預估體脂肪含量  女性腰臀比大於0.5會增加罹患心血管疾病的機率', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "03a6384fb1e1", "answer_pdf_sha1": "661e03be9c00", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "營養學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 13, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
